export function getAffirmationsByChapter(chapter: number): Affirmation[] {
  return AFFIRMATIONS.filter(a => a.chapter === chapter);
}

export function getRandomAffirmation(chapter?: number): Affirmation {
  const pool = chapter != null ? getAffirmationsByChapter(chapter) : AFFIRMATIONS;
  return pool[Math.floor(Math.random() * pool.length)];
}

export const AFFIRMATION_CHAPTERS = [1] as const;
